import React, { useState, useEffect, useCallback, useRef } from "react";
import {
  View,
  StyleSheet,
  Pressable,
  ActivityIndicator,
  Dimensions,
  Platform,
  Linking,
  TouchableOpacity,
} from "react-native";
import { useThemedAlert } from "@/components/ThemedAlert";
import { Image } from "expo-image";
import * as Location from "expo-location";
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withRepeat,
  withTiming,
  Easing,
  interpolate,
} from "react-native-reanimated";
import Svg, { Circle, Defs, RadialGradient, Stop, Path } from "react-native-svg";
import { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { RootStackParamList } from "@/navigation/RootNavigator";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/hooks/useAuth";
import { useTranslation } from "@/hooks/useLanguage";
import { Spacing, BorderRadius, Typography } from "@/constants/theme";
import { Feather } from "@expo/vector-icons";
import { getApiBaseUrl } from "@/constants/config";
import Slider from "@react-native-community/slider";

const { width } = Dimensions.get("window");
const RADAR_SIZE = Math.min(width - 60, 320);
const CENTER = RADAR_SIZE / 2;

interface NearbyUser {
  id: string;
  name: string;
  username?: string;
  age: number;
  gender: string;
  bio?: string;
  profilePhoto: string | null;
  distance: number;
  angle: number;
  online: boolean;
  verified: boolean;
  interests: string[];
}

type LoveRadarScreenNavigationProp = NativeStackNavigationProp<RootStackParamList, "LoveRadar">;

interface LoveRadarScreenProps {
  navigation: LoveRadarScreenNavigationProp;
}

export default function LoveRadarScreen({ navigation }: LoveRadarScreenProps) {
  const { theme } = useTheme();
  const { token, user, updateProfile } = useAuth(); // 'user' is now available for future use
  const { t } = useTranslation();
  const { showAlert, AlertComponent } = useThemedAlert();

  const [loading, setLoading] = useState(true);
  const [nearbyUsers, setNearbyUsers] = useState<NearbyUser[]>([]);
  const [locationPermission, setLocationPermission] = useState<boolean | null>(null);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [locationSharingEnabled, setLocationSharingEnabled] = useState(true);
  const [showFilters, setShowFilters] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);

  const [filters, setFilters] = useState({
    radius: 50,
    ageMin: 18,
    ageMax: 60,
    gender: "any" as "any" | "male" | "female",
  });

  const rotation = useSharedValue(0);
  const pulse = useSharedValue(1);
  const refreshInterval = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    rotation.value = withRepeat(
      withTiming(360, { duration: 4000, easing: Easing.linear }),
      -1,
      false
    );
    pulse.value = withRepeat(
      withTiming(1.3, { duration: 2000, easing: Easing.inOut(Easing.ease) }),
      -1,
      true
    );
  }, []);

  const scannerStyle = useAnimatedStyle(() => ({
    transform: [{ rotate: `${rotation.value}deg` }],
  }));

  const pulseStyle = useAnimatedStyle(() => ({
    transform: [{ scale: pulse.value }],
    opacity: interpolate(pulse.value, [1, 1.3], [0.5, 0]),
  }));

  const requestLocationPermission = async () => {
    try {
      const { status: existingStatus } = await Location.getForegroundPermissionsAsync();

      if (existingStatus === "denied") {
        showAlert(
          t('locationRequired'),
          'Please enable location access in your device settings to use Love Radar.',
          [
            { text: t('cancel'), style: 'cancel' },
            { 
              text: 'Open Settings', 
              style: 'default',
              onPress: () => Linking.openSettings()
            }
          ],
          'settings'
        );
        return null;
      }

      const { status } = await Location.requestForegroundPermissionsAsync();
      setLocationPermission(status === "granted");

      if (status === "granted") {
        const location = await Location.getCurrentPositionAsync({
          accuracy: Location.Accuracy.Balanced,
        });
        const coords = {
          lat: location.coords.latitude,
          lng: location.coords.longitude,
        };
        setUserLocation(coords);
        updateServerLocation(coords.lat, coords.lng);
        return coords;
      }
      return null;
    } catch (error) {
      console.error("Location permission error:", error);
      return null;
    }
  };

  const updateServerLocation = async (lat: number, lng: number) => {
    try {
      await fetch(`${getApiBaseUrl()}/api/radar/location`, {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ lat, lng }),
      });
    } catch (error) {
      console.error("Failed to update location:", error);
    }
  };

  const fetchNearbyUsers = useCallback(async (coords?: { lat: number; lng: number }) => {
    const location = coords || userLocation;
    if (!location || !token) return;

    try {
      const params = new URLSearchParams({
        lat: location.lat.toString(),
        lng: location.lng.toString(),
        radius: filters.radius.toString(),
        ageMin: filters.ageMin.toString(),
        ageMax: filters.ageMax.toString(),
        gender: filters.gender,
      });

      const response = await fetch(
        `${getApiBaseUrl()}/api/radar/nearby-users?${params}`,
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      const data = await response.json();
      if (data.success) {
        setNearbyUsers(data.users || []);
      }
    } catch (error) {
      console.error("Failed to fetch nearby users:", error);
    } finally {
      setLoading(false);
    }
  }, [userLocation, token, filters]);

  const toggleLocationSharing = async () => {
    try {
      const response = await fetch(`${getApiBaseUrl()}/api/radar/location-sharing`, {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ enabled: !locationSharingEnabled }),
      });

      const data = await response.json();
      if (data.success) {
        setLocationSharingEnabled(!locationSharingEnabled);
        showAlert(
          t('locationSharing'),
          locationSharingEnabled ? t('youAreHidden') : t('youAreVisible'),
          [{ text: t('ok'), style: 'default' }],
          locationSharingEnabled ? 'eye-off' : 'eye'
        );
      }
    } catch (error) {
      showAlert(t('error'), "Failed to update location sharing settings", [{ text: t('ok'), style: 'default' }], 'alert-circle');
    }
  };

  const handleRefreshLocation = useCallback(async () => {
    try {
      setLocationLoading(true);
      const { status } = await Location.requestForegroundPermissionsAsync();

      if (status !== 'granted') {
        showAlert(t('locationRequired'), t('enableLocationAccess'), [{ text: t('ok'), style: 'default' }], 'map-pin');
        setLocationLoading(false);
        return;
      }

      const location = await Location.getCurrentPositionAsync({
        accuracy: Location.Accuracy.Balanced,
      });

      const coords = {
        lat: location.coords.latitude,
        lng: location.coords.longitude,
      };

      setUserLocation(coords);
      setLocationPermission(true);
      await updateServerLocation(coords.lat, coords.lng);
      await updateProfile({ location: coords });
      await fetchNearbyUsers(coords);

      showAlert(t('success'), t('locationUpdated'), [{ text: t('ok'), style: 'default' }], 'check-circle');
    } catch (error) {
      console.error('Location refresh error:', error);
      showAlert(t('error'), t('locationError'), [{ text: t('ok'), style: 'default' }], 'alert-circle');
    } finally {
      setLocationLoading(false);
    }
  }, [token, updateProfile, fetchNearbyUsers, t, showAlert]);

  useEffect(() => {
    const init = async () => {
      const coords = await requestLocationPermission();
      if (coords) {
        await fetchNearbyUsers(coords);
      }
      setLoading(false);
    };
    init();

    return () => {
      if (refreshInterval.current) {
        clearInterval(refreshInterval.current);
      }
    };
  }, []);

  useEffect(() => {
    if (userLocation) {
      fetchNearbyUsers();
    }
  }, [filters]);

  const getUserDotPosition = (user: NearbyUser) => {
    const maxRadius = (RADAR_SIZE / 2 - 50);
    const distanceRatio = Math.min(user.distance / filters.radius, 1);
    const radius = distanceRatio * maxRadius;

    const angleRad = (user.angle * Math.PI) / 180;
    const x = CENTER + radius * Math.cos(angleRad);
    const y = CENTER + radius * Math.sin(angleRad);

    return { x, y };
  };

  const getGenderColor = (gender: string) => {
    return gender === "female" ? "#FF6B9D" : "#4A90E2";
  };

  const handleUserPress = (userId: string) => {
    navigation.navigate("ProfileDetail", { userId });
  };

  if (locationPermission === false) {
    return (
      <ScreenScrollView>
        <View style={styles.permissionContainer}>
          <View style={[styles.iconCircle, { backgroundColor: `${theme.primary}15` }]}>
            <Feather name="map-pin" size={48} color={theme.primary} />
          </View>
          <ThemedText style={styles.permissionTitle}>{t('enableLocation')}</ThemedText>
          <ThemedText style={styles.permissionText}>{t('locationNeeded')}</ThemedText>
          <Pressable style={[styles.permissionButton, { backgroundColor: theme.primary }]} onPress={requestLocationPermission}>
            <ThemedText style={{ color: '#FFF', fontWeight: '600' }}>{t('enableLocationAccess')}</ThemedText>
          </Pressable>
          <AlertComponent />
        </View>
      </ScreenScrollView>
    );
  }

  return (
    <ScreenScrollView contentContainerStyle={{ paddingBottom: 40 }}>
      <View style={styles.container}>

        {/* --- LAYER 1: TOP NAV BAR --- */}
        <View style={styles.topHeader}>
          <View style={styles.headerLeft}>
            <TouchableOpacity 
              style={[styles.backButton, { backgroundColor: theme.surface }]} 
              onPress={() => navigation.goBack()}
            >
              <Feather name="arrow-left" size={24} color={theme.text} />
            </TouchableOpacity>
          </View>
          <ThemedText style={[styles.pageTitle, { color: theme.text }]}>Love Radar</ThemedText>
          <View style={styles.headerRight} />
        </View>

        {/* --- LAYER 2: INFO & BUTTONS ROW --- */}
        <View style={styles.headerRow}>
          <View style={styles.headerInfo}>
            <ThemedText style={[styles.subtitle, { color: theme.textSecondary }]}>
              {nearbyUsers.length > 0
                ? `${nearbyUsers.length} ${t('peopleWithinKm')}\n${filters.radius}km`
                : t('scanningNearby')}
            </ThemedText>
          </View>

          <View style={styles.headerButtons}>
            <Pressable
              style={[styles.headerButton, { backgroundColor: theme.surface }]}
              onPress={handleRefreshLocation}
              disabled={locationLoading}
            >
              {locationLoading ? (
                <ActivityIndicator size="small" color={theme.primary} />
              ) : (
                <Feather name="map-pin" size={20} color="#F2994A" />
              )}
            </Pressable>

            <Pressable
              style={[styles.headerButton, { backgroundColor: theme.surface }]}
              onPress={() => setShowFilters(!showFilters)}
            >
              <Feather name="sliders" size={20} color="#F2994A" />
            </Pressable>

            <Pressable
              style={[
                styles.headerButton,
                { backgroundColor: locationSharingEnabled ? theme.online : theme.surface },
              ]}
              onPress={toggleLocationSharing}
            >
              <Feather
                name={locationSharingEnabled ? "eye" : "eye-off"}
                size={20}
                color={locationSharingEnabled ? "#fff" : theme.textSecondary}
              />
            </Pressable>
          </View>
        </View>

        {/* --- FILTERS CARD --- */}
        {showFilters && (
          <View style={[styles.filtersCard, { backgroundColor: theme.surface }]}>
            <View style={styles.filterRow}>
              <ThemedText style={styles.filterLabel}>{t('distance')}: {filters.radius}km</ThemedText>
              <Slider
                style={styles.slider}
                minimumValue={1}
                maximumValue={100}
                value={filters.radius}
                onValueChange={(v) => setFilters({ ...filters, radius: v })}
                minimumTrackTintColor={theme.primary}
                thumbTintColor={theme.primary}
              />
            </View>
            <View style={styles.filterRow}>
              <ThemedText style={styles.filterLabel}>{t('show')}</ThemedText>
              <View style={styles.genderButtons}>
                {(["any", "male", "female"] as const).map((g) => (
                  <Pressable
                    key={g}
                    style={[styles.genderButton, filters.gender === g && { backgroundColor: theme.primary }]}
                    onPress={() => setFilters({ ...filters, gender: g })}
                  >
                    <ThemedText style={[styles.genderButtonText, filters.gender === g && styles.genderButtonTextActive]}>
                      {g === "any" ? t('everyone') : g === "male" ? t('male') : t('female')}
                    </ThemedText>
                  </Pressable>
                ))}
              </View>
            </View>
            <Pressable style={[styles.applyButton, { backgroundColor: theme.primary }]} onPress={() => setShowFilters(false)}>
              <ThemedText style={{ color: '#FFF', fontWeight: '700' }}>{t('applyFilters')}</ThemedText>
            </Pressable>
          </View>
        )}

        {/* --- RADAR CARD --- */}
        <View style={[styles.radarCard, { backgroundColor: theme.surface }]}>
          <View style={styles.radarContainer}>
            <Svg width={RADAR_SIZE} height={RADAR_SIZE}>
              {[0.25, 0.5, 0.75, 1].map((f, i) => (
                <Circle key={i} cx={CENTER} cy={CENTER} r={(RADAR_SIZE / 2 - 30) * f} stroke={theme.border} strokeDasharray="4,4" fill="none" opacity={0.4} />
              ))}
              <Circle cx={CENTER} cy={CENTER} r="10" fill={theme.primary} />
            </Svg>

            <Animated.View style={[styles.pulseRing, pulseStyle]}>
              <View style={[styles.ring, { borderColor: theme.primary }]} />
            </Animated.View>

            <Animated.View style={[styles.scannerBeam, scannerStyle]}>
              <Svg width={RADAR_SIZE} height={RADAR_SIZE}>
                <Defs>
                  <RadialGradient id="beamGrad" cx="50%" cy="50%">
                    <Stop offset="0%" stopColor={theme.primary} stopOpacity="0.3" />
                    <Stop offset="100%" stopColor={theme.primary} stopOpacity="0" />
                  </RadialGradient>
                </Defs>
                <Path d={`M ${CENTER} ${CENTER} L ${CENTER} 30 A ${CENTER - 30} ${CENTER - 30} 0 0 1 ${RADAR_SIZE - 30} ${CENTER} Z`} fill="url(#beamGrad)" />
              </Svg>
            </Animated.View>

            {nearbyUsers.map((u) => {
              const pos = getUserDotPosition(u);
              return (
                <Pressable key={u.id} style={[styles.userDot, { left: pos.x - 22, top: pos.y - 22, backgroundColor: getGenderColor(u.gender) }]} onPress={() => handleUserPress(u.id)}>
                  {u.profilePhoto ? <Image source={{ uri: u.profilePhoto }} style={styles.userDotImage} /> : <Feather name="user" size={16} color="#fff" />}
                  {u.online && <View style={styles.onlineIndicator} />}
                </Pressable>
              );
            })}

            <View style={[styles.scanningBadge, { backgroundColor: theme.online }]}>
              <View style={styles.scanningDot} />
              <ThemedText style={styles.scanningText}>{locationSharingEnabled ? t('live') : t('hidden')}</ThemedText>
            </View>
          </View>

          <View style={styles.distanceLabels}>
            <ThemedText style={styles.distanceLabel}>0</ThemedText>
            <ThemedText style={styles.distanceLabel}>{Math.round(filters.radius/2)}km</ThemedText>
            <ThemedText style={styles.distanceLabel}>{filters.radius}km</ThemedText>
          </View>
        </View>

        {/* --- LEGEND --- */}
        <View style={styles.legend}>
          <View style={styles.legendItem}><View style={[styles.legendDot, { backgroundColor: theme.primary }]} /><ThemedText style={styles.legendText}>{t('you')}</ThemedText></View>
          <View style={styles.legendItem}><View style={[styles.legendDot, { backgroundColor: "#FF6B9D" }]} /><ThemedText style={styles.legendText}>{t('women')}</ThemedText></View>
          <View style={styles.legendItem}><View style={[styles.legendDot, { backgroundColor: "#4A90E2" }]} /><ThemedText style={styles.legendText}>{t('men')}</ThemedText></View>
        </View>

        {/* --- LIST SECTION --- */}
        <View style={styles.nearbyListSection}>
          <ThemedText style={styles.sectionTitle}>{t('peopleNearby')}</ThemedText>
          {nearbyUsers.map((u) => (
            <Pressable key={u.id} style={[styles.userCard, { backgroundColor: theme.surface }]} onPress={() => handleUserPress(u.id)}>
              <View style={styles.userCardLeft}>
                <Image source={{ uri: u.profilePhoto || '' }} style={styles.userCardPhoto} />
                <View style={styles.userCardInfo}>
                   <View style={styles.userCardNameRow}>
                     <ThemedText style={styles.userCardName}>{u.name}, {u.age}</ThemedText>
                     {u.verified && <Feather name="check-circle" size={14} color={theme.primary} style={{marginLeft: 4}}/>}
                   </View>
                   <ThemedText style={styles.userCardDistance}>{u.distance.toFixed(1)} km away</ThemedText>
                </View>
              </View>
              <Feather name="chevron-right" size={20} color={theme.textSecondary} />
            </Pressable>
          ))}
        </View>

        <AlertComponent />
      </View>
    </ScreenScrollView>
  );
}

